#include <bits/stdc++.h>using namespace std;typedef long long ll;int main() {    ll t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);        for(int i=0;i<n;i++)cin>>a[i];        ll ans=0;        for(int i=0;i<n;i++){            for(ll d=a[i];d<=min(n,a[i]*a[i]);d+=a[i]){                if(i+d<n&&a[i]*a[i+d]==d)ans++;                if(i-d>=0&&a[i]*a[i-d]==d&&a[i]!=a[i-d])ans++;            }        }        cout<<ans<<endl;    }}